/// <summary>
/// Batch entry point invoked by the SysOperation controller.
/// </summary>
public void process(ConDemoBatchContract _contract)
{
    info(strFmt("Effective batch size: %1", this.calculateEffectiveBatchSize(_contract)));
}

/// <summary>
/// Pure, deterministic helper: the requested batch size scaled by the priority factor.
/// </summary>
public int calculateEffectiveBatchSize(ConDemoBatchContract _contract)
{
    return _contract.parmBatchSize() * _contract.parmPriorityFactor();
}
